import numpy as npimport matplotlib.pyplot as plt# Function to print the DP matrixdef pprint_matrix(M, pattern, text):    try:        if (len(pattern) + 1 != len(M)) or (len(text) + 1 != len(M[0])):            raise Exception('Invalid matrix dimensions')        print('    ', end='')        for idx in range(len(M[0]) - 1):            print(text[idx], end=' ')        print()        for ridx, row in enumerate(M):            for cidx, col in enumerate(range(len(row) + 1)):                try:                    if cidx == 0:                        if ridx == 0:                            print(' ', end='')                        else:                            print(pattern[ridx - 1], end='')                        continue                    else:                        print(M[ridx][cidx - 1], end='')                finally:                    print(' ', end='')            print()    except Exception as e:        print(f'Invalid dynamic programming matrix! Are you sure you are creating the matrix with the correct dimensions?')        raise e# Function to compute the DP matrix and backtracedef edit_distance_dp(pattern, text):    # Initialize the DP Matrix (M)    m = len(pattern)    n = len(text)    M = [[0] * (n + 1) for _ in range(m + 1)]    print('Dynamic programming matrix initialized:')    pprint_matrix(M, pattern, text)    # Initialize the first column and row    for i in range(m + 1):        M[i][0] = i    for j in range(n + 1):        M[0][j] = j    print('M matrix after initializing the first column and row:')    pprint_matrix(M, pattern, text)    # Fill the rest of the DP matrix    for i in range(1, m + 1):        for j in range(1, n + 1):            if pattern[i - 1] == text[j - 1]:                num = 0  # No penalty for match            else:                num = 1  # Penalty for mismatch            insertion = M[i - 1][j]            deletion = M[i][j - 1]            mismatch_match = M[i - 1][j - 1]            M[i][j] = min(insertion + 1, deletion + 1, mismatch_match + num)    print('After filling the M matrix:')    pprint_matrix(M, pattern, text)    # Call backtrace_dp to get the distance and cigar    distance, cigar, backtrace_path = backtrace_dp(M, pattern, text)    return M, (distance, cigar, backtrace_path)# Function to backtrace the DP matrixdef backtrace_dp(M, pattern, text):    v = len(pattern)    h = len(text)    cigar = ''    distance = M[v][h]    backtrace_path = [(v, h)]  # Start at the bottom-right corner    while v > 0 and h > 0:        if M[v][h] == M[v - 1][h] + 1:  # Deletion            cigar = 'D' + cigar            v -= 1        elif M[v][h] == M[v][h - 1] + 1:  # Insertion            cigar = 'I' + cigar            h -= 1        else:  # Match or Mismatch            if pattern[v - 1] == text[h - 1]:                cigar = 'M' + cigar  # Match            else:                cigar = 'X' + cigar  # Mismatch            v -= 1            h -= 1        backtrace_path.append((v, h))    # Handle remaining borders    while v > 0:        cigar = 'D' + cigar        v -= 1        backtrace_path.append((v, h))    while h > 0:        cigar = 'I' + cigar        h -= 1        backtrace_path.append((v, h))    backtrace_path.reverse()  # Reverse to start from the top-left    return distance, cigar, backtrace_path# Function to visualize the alignment tabledef visualize_alignment_table(M, pattern, text, backtrace_path):    fig, ax = plt.subplots(figsize=(8, 6))    # Create the heatmap    cax = ax.matshow(M, cmap="coolwarm")    plt.colorbar(cax)    # Set axis labels    ax.set_xticks(np.arange(len(text) + 1))    ax.set_yticks(np.arange(len(pattern) + 1))    ax.set_xticklabels(['-'] + list(text))    ax.set_yticklabels(['-'] + list(pattern))    # Annotate each cell with the alignment score    for i in range(len(pattern) + 1):        for j in range(len(text) + 1):            ax.text(j, i, str(M[i][j]), ha='center', va='center', color='black')    # Highlight the backtrace path with blue outlines    for (i, j) in backtrace_path:        rect = plt.Rectangle((j - 0.5, i - 0.5), 1, 1, edgecolor='black', fill=False, linewidth=2)        ax.add_patch(rect)    # Set title and labels    plt.title("Sequence Alignment Table", weight="bold")    plt.xlabel("Text")    plt.ylabel("Pattern")    plt.show()# Main scriptif __name__ == "__main__":    pattern = "BARCELONA"    text = "BADALONA"    # Compute the DP matrix and backtrace    M, (distance, cigar, backtrace_path) = edit_distance_dp(pattern, text)    print(f'The distance between {pattern} and {text} is: {distance}')    print(f'The cigar is: {cigar}')    print(f'Backtrace path: {backtrace_path}')    # Visualize the alignment table with the backtrace highlighted    visualize_alignment_table(M, pattern, text, backtrace_path)